"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";

export default function PublishPage() {
  const router = useRouter();
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [skillContent, setSkillContent] = useState("");
  const [tags, setTags] = useState("");
  const [authorName, setAuthorName] = useState("");
  const [authorUrl, setAuthorUrl] = useState("");
  const [landingHtml, setLandingHtml] = useState("");
  const [portfolioHtml, setPortfolioHtml] = useState("");
  const [blogHtml, setBlogHtml] = useState("");

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!name.trim() || !skillContent.trim() || !authorName.trim()) return;

    setSubmitting(true);
    setError(null);

    try {
      const res = await fetch("/api/styles", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: name.trim(),
          description: description.trim() || undefined,
          skillContent: skillContent.trim(),
          tags: tags.trim() || undefined,
          authorName: authorName.trim(),
          authorUrl: authorUrl.trim() || undefined,
          pages: [
            landingHtml.trim() && { pageType: "landing", htmlContent: landingHtml.trim() },
            portfolioHtml.trim() && { pageType: "portfolio", htmlContent: portfolioHtml.trim() },
            blogHtml.trim() && { pageType: "blog", htmlContent: blogHtml.trim() },
          ].filter(Boolean),
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.error || "Publish failed");
      }

      const data = await res.json();
      router.push(`/style/${data.id}`);
    } catch (err: any) {
      setError(err.message);
      setSubmitting(false);
    }
  }

  const inputClass =
    "w-full px-4 py-2.5 rounded-lg bg-neutral-900 border border-neutral-800 text-white placeholder-neutral-500 focus:outline-none focus:border-purple-500";

  return (
    <div className="max-w-2xl mx-auto px-6 py-16">
      <h1 className="text-3xl font-bold mb-2">Publish a Style</h1>
      <p className="text-neutral-400 mb-8">
        Share your design skill with the community.
      </p>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-neutral-300 mb-2">
            Style Name *
          </label>
          <input
            type="text"
            required
            value={name}
            onChange={(e) => setName(e.target.value)}
            className={inputClass}
            placeholder="Neo-Brutalist"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-neutral-300 mb-2">
            Description
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={3}
            className={inputClass}
            placeholder="A bold, raw design style..."
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-neutral-300 mb-2">
            Skill Content *
          </label>
          <textarea
            required
            value={skillContent}
            onChange={(e) => setSkillContent(e.target.value)}
            rows={12}
            className={`${inputClass} font-mono text-sm`}
            placeholder="Paste your skill markdown here..."
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-neutral-300 mb-2">
            Tags (comma-separated)
          </label>
          <input
            type="text"
            value={tags}
            onChange={(e) => setTags(e.target.value)}
            className={inputClass}
            placeholder="brutalist, bold, modern"
          />
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-neutral-300 mb-2">
              Author Name *
            </label>
            <input
              type="text"
              required
              value={authorName}
              onChange={(e) => setAuthorName(e.target.value)}
              className={inputClass}
              placeholder="Jane Doe"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-neutral-300 mb-2">
              Author URL
            </label>
            <input
              type="url"
              value={authorUrl}
              onChange={(e) => setAuthorUrl(e.target.value)}
              className={inputClass}
              placeholder="https://yoursite.com"
            />
          </div>
        </div>

        <details className="group">
          <summary className="cursor-pointer text-sm text-neutral-400 hover:text-neutral-300">
            Add example pages (optional)
          </summary>
          <div className="mt-4 space-y-4">
            <div>
              <label className="block text-sm font-medium text-neutral-300 mb-2">
                Landing Page HTML
              </label>
              <textarea
                value={landingHtml}
                onChange={(e) => setLandingHtml(e.target.value)}
                rows={6}
                className={`${inputClass} font-mono text-sm`}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-300 mb-2">
                Portfolio Page HTML
              </label>
              <textarea
                value={portfolioHtml}
                onChange={(e) => setPortfolioHtml(e.target.value)}
                rows={6}
                className={`${inputClass} font-mono text-sm`}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-neutral-300 mb-2">
                Blog Page HTML
              </label>
              <textarea
                value={blogHtml}
                onChange={(e) => setBlogHtml(e.target.value)}
                rows={6}
                className={`${inputClass} font-mono text-sm`}
              />
            </div>
          </div>
        </details>

        {error && <p className="text-red-400 text-sm">{error}</p>}

        <button
          type="submit"
          disabled={submitting || !name.trim() || !skillContent.trim() || !authorName.trim()}
          className="w-full px-6 py-3 rounded-lg bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-medium transition-colors"
        >
          {submitting ? "Publishing..." : "Publish Style"}
        </button>
      </form>
    </div>
  );
}
